plist.dict:
CFBundlePackageType
APPL
CFBundleName
{{.Info.ProductName}}
CFBundleExecutable
{{.OutputFilename}}
CFBundleIdentifier
com.angelmsger.o3
CFBundleVersion
{{.Info.ProductVersion}}
CFBundleGetInfoString
{{.Info.Comments}}
CFBundleShortVersionString
{{.Info.ProductVersion}}
CFBundleIconFile
iconfile
LSMinimumSystemVersion
11.0.0
NSHighResolutionCapable
true
NSHumanReadableCopyright
{{.Info.Copyright}}

SUFeedURL
https://github.com/AngelMsger/o3/releases/latest/download/appcast.xml
SUPublicEDKey

SUEnableAutomaticChecks

{{if .Info.FileAssociations}}
CFBundleDocumentTypes

  {{range .Info.FileAssociations}}

    CFBundleTypeExtensions

      {{.Ext}}

    CFBundleTypeName
    {{.Name}}
    CFBundleTypeRole
    {{.Role}}
    CFBundleTypeIconFile
    {{.IconName}}

  {{end}}

{{end}}
{{if .Info.Protocols}}
CFBundleURLTypes

  {{range .Info.Protocols}}

        CFBundleURLName
        com.wails.{{.Scheme}}
        CFBundleURLSchemes

            {{.Scheme}}

        CFBundleTypeRole
        {{.Role}}

  {{end}}

{{end}}
